#include<bits/stdc++.h>
using namespace std;
bool mp[1001][1001],vis[1001];
int n,m,a[1001],b[1001],dp[1001];
int calc(int x)
{
    if(dp[x]!=-1)
    {
        return dp[x];
    }
    dp[x]=0;
    for(int i=1;i<=n;i++)
    {
        if(mp[x][i])
        {
            dp[x]=max(dp[x],calc(i)+1);
        }
    }
    return dp[x];
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int c;
        scanf("%d",&c);
        int cnt=0;
        memset(vis,0,sizeof(vis));
        for(int j=1;j<=c;j++)
        {
            scanf("%d",&a[j]);
            vis[a[j]]=1;
        }
        for(int j=a[1];j<=a[c];j++)
        {
            if(!vis[j])
            {
                b[++cnt]=j;
            }
        }
        for(int j=1;j<=c;j++)
        {
            for(int k=1;k<=cnt;k++)
            {
                mp[a[j]][b[k]]=1;
            }
        }
    }
    memset(dp,-1,sizeof(dp));
    int ans=-1;
    for(int i=1;i<=n;i++)
    {
        ans=max(ans,calc(i));
    }
    printf("%d",ans+1);
    return 0;
}
